import{_ as e,c as o,o as a,ae as r}from"./chunks/framework.B7Y1jjX-.js";const c=JSON.parse('{"title":"MVVM与MVC","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/前端/基本概念/MVVM与MVC.md","filePath":"generated-notes/前端/基本概念/MVVM与MVC.md"}'),l={name:"generated-notes/前端/基本概念/MVVM与MVC.md"};function d(i,t,n,s,V,M){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="mvvm与mvc" tabindex="-1">MVVM与MVC <a class="header-anchor" href="#mvvm与mvc" aria-label="Permalink to &quot;MVVM与MVC&quot;">​</a></h1><h2 id="_1-mvc" tabindex="-1">1 MVC <a class="header-anchor" href="#_1-mvc" aria-label="Permalink to &quot;1 MVC&quot;">​</a></h2><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/56662504fb1b43de86e6b663697945da~tplv-k3u1fbpfcp-jj-mark:3024:0:0:0:q75.awebp#?w=743&amp;h=382&amp;s=66496&amp;e=png&amp;b=fdfafa" alt="image.png"></p><h3 id="mvc组成" tabindex="-1">MVC组成 <a class="header-anchor" href="#mvc组成" aria-label="Permalink to &quot;MVC组成&quot;">​</a></h3><p><strong>MVC思想</strong> ：Controller负责将Model的数据用View显示出来。</p><table tabindex="0"><thead><tr><th>MVC</th><th>解释</th></tr></thead><tbody><tr><td>① Model（模型）</td><td>是应用程序中<strong>用于处理应用程序数据逻辑</strong>的部分。 &lt;br&gt;通常模型对象负责<strong>在数据库中存取数据</strong>。处理数据的crud</td></tr><tr><td>② View（视图）</td><td>是应用程序中处理<strong>数据显示</strong>的部分。通常视图是依据模型数据创建的。视图层，前端</td></tr><tr><td>③ Controller（控制器）</td><td>是应用程序中处理<strong>用户交互</strong>的部分。 &lt;br&gt;<strong>控制器负责从视图读取数据，控制用户输入，并将数据发送给模型。</strong> &lt;br&gt;一般包括业务处理模块和router路由模块</td></tr></tbody></table><h3 id="mvc优点" tabindex="-1">MVC优点 <a class="header-anchor" href="#mvc优点" aria-label="Permalink to &quot;MVC优点&quot;">​</a></h3><ul><li><strong>耦合度低</strong>（运用MVC的应用程序的三个部件是相互独立的，改变其中一个不会影响其他两个）；</li><li>重用性高（多个视图可以使用同一个模型）</li><li>生命周期成本低</li><li>部署快（业务分工明确）</li><li><strong>可维护性高</strong></li></ul><h3 id="mvc缺点" tabindex="-1">MVC缺点： <a class="header-anchor" href="#mvc缺点" aria-label="Permalink to &quot;MVC缺点：&quot;">​</a></h3><ul><li>不适合小型项目开发</li><li><strong>视图与控制器联系过于紧密</strong>，妨碍了它们的独立重用</li></ul><h2 id="_2-mvvm——视图模型双向绑定-谈谈你对mvvm开发模式的理解" tabindex="-1">2 MVVM——视图模型双向绑定（谈谈你对MVVM开发模式的理解） <a class="header-anchor" href="#_2-mvvm——视图模型双向绑定-谈谈你对mvvm开发模式的理解" aria-label="Permalink to &quot;2 MVVM——视图模型双向绑定（谈谈你对MVVM开发模式的理解）&quot;">​</a></h2><p><img src="https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/86732b9278e74d6c857d72ea77995d2d~tplv-k3u1fbpfcp-jj-mark:3024:0:0:0:q75.awebp#?w=796&amp;h=411&amp;s=20174&amp;e=png&amp;b=fefdfd" alt="image.png"></p><h3 id="mvvm-组成" tabindex="-1">MVVM 组成： <a class="header-anchor" href="#mvvm-组成" aria-label="Permalink to &quot;MVVM 组成：&quot;">​</a></h3><p>MVVM由Model，View，ViewModel三部分构成。</p><table tabindex="0"><thead><tr><th>M V VM</th><th>解释</th></tr></thead><tbody><tr><td>Model</td><td>代表数据模型（Vue的data），<strong>数据和业务逻辑</strong>都在Model层中定义；</td></tr><tr><td>View</td><td>代表UI视图，负责<strong>数据的展示</strong>（Vue的el）；</td></tr><tr><td>ViewModel</td><td>是一个对象，负责<strong>监听 Model 中数据的改变</strong>并且<strong>控制View视图的更新</strong>，处理用户交互操作；</td></tr></tbody></table><ul><li><strong>Model</strong> 和 <strong>View</strong> 并无直接关联，而是通过 <strong>ViewModel</strong> 来进行交互的（即双向数据绑定），</li><li><strong>Model</strong> 和 <strong>ViewModel</strong>之间有着<strong>双向数据绑定的联系</strong>。<br> View的变化可以引起Model的变化，Model的变化也可以引起View变化（类似于浅拷贝）。<code>ViewModel</code>是<code>View</code>和<code>Model</code>层的桥梁，数据会绑定到<code>viewModel</code>层并自动将数据渲染到页面中，视图变化的时候会通知<code>viewModel</code>层更新数据。</li></ul><h3 id="mvvm-优点" tabindex="-1">MVVM 优点： <a class="header-anchor" href="#mvvm-优点" aria-label="Permalink to &quot;MVVM 优点：&quot;">​</a></h3><ul><li>低耦合： <ul><li>视图（View）可以独立于Model变化和修改，<strong>一个Model可以绑定到不同的View上</strong>，</li><li>当View变化的时候Model可以不变化，当Model变化的时候View也可以不变；</li></ul></li><li>可重用性：你可以把一些视图逻辑放在一个Model里面，让很多View重用这段视图逻辑。</li><li>独立开发：<strong>双向数据绑定的模式，实现了View和Model的自动同步，因此开发者只需要专注对数据的维护操作即可，而不需要一直操作 dom。</strong><br> 可以实现双向绑定的标签：Input，textarea，select标签等（可以输入或改变标签内容的标签）</li></ul><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/4e8980cd36bb4c78856500307dd289f9~tplv-k3u1fbpfcp-jj-mark:3024:0:0:0:q75.awebp#?w=720&amp;h=483&amp;s=38876&amp;e=jpg&amp;b=fbf9fc" alt="MVVM2.png"></p><ul><li>MVVM 和 MVC都是一种设计思想。</li><li>MVVM 与 MVC 最大的<strong>区别</strong>就是：它实现了<strong>View和Model的自动同步</strong><ul><li>当Model属性改变时，不用手动操作Dom元素去改变View的显示。</li><li>而改变属性后，该属性对应View的显示会自动改变</li></ul></li></ul>',20)])])}const g=e(l,[["render",d]]);export{c as __pageData,g as default};
